import math

def handle_special_floats(value):
    if math.isnan(value):
        return "NaN detected"
    elif math.isinf(value):
        if value > 0:
            return "Positive infinity"
        else:
            return "Negative infinity"
    else:
        return f"Normal float: {value}"

# 使用示例
print(handle_special_floats(float('inf')))
print(handle_special_floats(float('-inf')))
print(handle_special_floats(float('nan')))
print(handle_special_floats(3.14))
